#include <bits/stdc++.h>
using namespace std;
int main(){
    int n; cin >> n;
    vector<pair<long long,long long>> a(n);
    for (auto &p : a) cin >> p.first >> p.second;
    sort(a.begin(), a.end(), [](auto&x, auto&y){return x.second < y.second;});
    long long cur = LLONG_MIN; int cnt = 0;
    for (auto &p : a) if (p.first >= cur) { cnt++; cur = p.second; }
    cout << cnt << '\n';
}
